// CF09 WF_AI_COACH — validate payload, ensure a coach_sessions row exists,
// load session history + fresh context for the prompt.
// Global fetch + $env per MEMORY.md.

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || raw;

const projectId = payload.project_id;
const userMessage = typeof payload.user_message === 'string' ? payload.user_message.trim() : '';
let sessionId = payload.session_id || null;
let focusArea = payload.focus_area || null;

if (!projectId) {
  return [{ json: { success: false, error: 'project_id is required', http_status: 400, via_webhook: viaWebhook } }];
}
if (!userMessage) {
  return [{ json: { success: false, error: 'user_message is required (non-empty string)', http_status: 400, via_webhook: viaWebhook } }];
}
if (userMessage.length > 8000) {
  return [{ json: { success: false, error: 'user_message exceeds 8000 chars', http_status: 400, via_webhook: viaWebhook } }];
}

const VALID_FOCUS = ['growth', 'monetization', 'competitors', 'content', 'general'];
if (focusArea && !VALID_FOCUS.includes(focusArea)) focusArea = null;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

async function sbGet(url) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) throw new Error(`HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

// 1. Verify project exists + load project context
let project = null;
try {
  const arr = await sbGet(`${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=id,name,niche,niche_description,niche_rpm_category,estimated_rpm_mid,niche_health_score`);
  project = (arr && arr[0]) || null;
} catch (e) {
  return [{ json: { success: false, error: `Failed to load project: ${e.message}`, http_status: 500, via_webhook: viaWebhook } }];
}
if (!project) {
  return [{ json: { success: false, error: `Project ${projectId} not found`, http_status: 404, via_webhook: viaWebhook } }];
}

// 2. Ensure session exists (create if session_id missing)
let session = null;
let isNewSession = false;

if (sessionId) {
  try {
    const arr = await sbGet(`${supabaseUrl}/rest/v1/coach_sessions?id=eq.${sessionId}&select=id,project_id,title,focus_area,message_count,total_input_tokens,total_output_tokens,estimated_cost_usd,is_archived`);
    session = (arr && arr[0]) || null;
  } catch (e) {
    return [{ json: { success: false, error: `Failed to load session: ${e.message}`, http_status: 500, via_webhook: viaWebhook } }];
  }
  if (!session) {
    return [{ json: { success: false, error: `Session ${sessionId} not found`, http_status: 404, via_webhook: viaWebhook } }];
  }
  if (session.project_id !== projectId) {
    return [{ json: { success: false, error: 'Session belongs to a different project', http_status: 403, via_webhook: viaWebhook } }];
  }
  if (session.is_archived) {
    return [{ json: { success: false, error: 'Session is archived', http_status: 409, via_webhook: viaWebhook } }];
  }
} else {
  // Create new session
  try {
    const insertRes = await fetch(`${supabaseUrl}/rest/v1/coach_sessions`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=representation' },
      body: JSON.stringify({
        project_id: projectId,
        focus_area: focusArea || 'general',
        title: null,
        message_count: 0,
        total_input_tokens: 0,
        total_output_tokens: 0,
        estimated_cost_usd: 0,
        is_archived: false
      })
    });
    if (!insertRes.ok) {
      return [{ json: { success: false, error: `Create session failed: HTTP ${insertRes.status}: ${(await insertRes.text()).slice(0, 200)}`, http_status: 500, via_webhook: viaWebhook } }];
    }
    const arr = await insertRes.json();
    session = Array.isArray(arr) && arr[0] ? arr[0] : null;
    if (!session) {
      return [{ json: { success: false, error: 'Create session returned empty body', http_status: 500, via_webhook: viaWebhook } }];
    }
    sessionId = session.id;
    isNewSession = true;
  } catch (e) {
    return [{ json: { success: false, error: `Create session exception: ${e.message}`, http_status: 500, via_webhook: viaWebhook } }];
  }
}

const effectiveFocusArea = session.focus_area || 'general';

// 3. Load history (existing turns) ordered by turn_index ascending
let history = [];
let prevMaxTurnIndex = -1;
if (!isNewSession) {
  try {
    history = await sbGet(`${supabaseUrl}/rest/v1/coach_messages?session_id=eq.${sessionId}&select=turn_index,role,content&order=turn_index.asc&limit=200`);
    if (Array.isArray(history) && history.length > 0) {
      prevMaxTurnIndex = history.reduce((mx, h) => Math.max(mx, Number(h.turn_index) || 0), -1);
    }
  } catch (_) { /* non-fatal — treat as empty history */ }
}

// 4. Load live context (best-effort, parallel)
const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
const urls = {
  topics: `${supabaseUrl}/rest/v1/topics?project_id=eq.${projectId}&select=seo_title,selected_title,predicted_performance_score,yt_views,yt_ctr,status&order=created_at.desc&limit=10`,
  alerts: `${supabaseUrl}/rest/v1/competitor_alerts?project_id=eq.${projectId}&is_read=eq.false&select=title,severity,alert_type,created_at&order=created_at.desc&limit=5`,
  ideas: `${supabaseUrl}/rest/v1/daily_ideas?project_id=eq.${projectId}&status=eq.pending&select=idea_title,combined_score&order=created_at.desc&limit=5`
};

let recentTopics = [];
let unreadAlerts = [];
let pendingIdeas = [];
try { recentTopics = await sbGet(urls.topics); } catch (_) {}
try { unreadAlerts = await sbGet(urls.alerts); } catch (_) {}
try { pendingIdeas = await sbGet(urls.ideas); } catch (_) {}

return [{
  json: {
    project_id: projectId,
    session_id: sessionId,
    is_new_session: isNewSession,
    session,
    project,
    focus_area: effectiveFocusArea,
    user_message: userMessage,
    history: Array.isArray(history) ? history : [],
    prev_max_turn_index: prevMaxTurnIndex,
    context: {
      recent_topics: recentTopics || [],
      unread_alerts: unreadAlerts || [],
      pending_ideas: pendingIdeas || []
    },
    via_webhook: viaWebhook,
    started_at: new Date().toISOString()
  }
}];

// Assemble messages + inline system prompt, call Claude Opus 4.6 with backoff.
const data = $input.first().json;
if (data.success === false) return $input.item;

const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const project = data.project || {};
const ctx = data.context || {};
const history = Array.isArray(data.history) ? data.history : [];
const userMessage = data.user_message;
const focusArea = data.focus_area || 'general';

// Derive context stats
const ppsValues = (ctx.recent_topics || []).map(t => Number(t.predicted_performance_score)).filter(v => Number.isFinite(v));
const minPps = ppsValues.length ? Math.min(...ppsValues) : null;
const maxPps = ppsValues.length ? Math.max(...ppsValues) : null;

const ctrValues = (ctx.recent_topics || []).map(t => Number(t.yt_ctr)).filter(v => Number.isFinite(v) && v > 0);
const avgCtr = ctrValues.length ? (ctrValues.reduce((a, b) => a + b, 0) / ctrValues.length).toFixed(2) : null;

const alertCount = (ctx.unread_alerts || []).length;
const topAlert = alertCount > 0 ? String(ctx.unread_alerts[0].title || '').slice(0, 160) : '';
const ideaCount = (ctx.pending_ideas || []).length;

const nicheHealth = project.niche_health_score != null ? project.niche_health_score : 'n/a';
const rpmCat = project.niche_rpm_category || 'uncategorized';
const rpmMid = project.estimated_rpm_mid != null ? Number(project.estimated_rpm_mid) : 0;
const name = project.name || '(unnamed)';
const niche = project.niche || 'general';

const systemPrompt = `You are Vision GridAI's growth coach for project "${name}" (${niche}). You know this channel's recent performance, competitor activity, and pending idea backlog. Give SHORT, SPECIFIC, DATA-BACKED advice. No hedging. No generic tips. When recommending action, cite the exact number or competitor. If the user asks something you can't answer from context, say so and suggest what data to gather.

Focus area: ${focusArea}.

Context:
- Niche: ${niche} (${rpmCat}, ~$${rpmMid}/1K RPM)
- Niche health: ${nicheHealth}/100
- Recent topic PPS range: ${minPps != null ? `${minPps}-${maxPps}` : 'n/a'}
- Last 10 topics avg CTR: ${avgCtr != null ? avgCtr + '%' : 'n/a'}
- Unread competitor alerts: ${alertCount}${topAlert ? ` (${topAlert})` : ''}
- Pending ideas ready: ${ideaCount}

Keep responses under 200 words unless the question demands more. Format with bullets when listing concrete actions.`;

// Build messages array — past turns + new user message
const messages = [];
for (const h of history) {
  if (!h || !h.role || !h.content) continue;
  if (h.role !== 'user' && h.role !== 'assistant') continue; // skip system rows
  messages.push({ role: h.role, content: String(h.content) });
}
messages.push({ role: 'user', content: userMessage });

// Trim history if it runs long: keep the last 20 turns + the new user turn.
let trimmedMessages = messages;
if (messages.length > 21) {
  trimmedMessages = messages.slice(messages.length - 21);
}

async function callClaude(maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-opus-4-6',
          max_tokens: 1200,
          system: systemPrompt,
          messages: trimmedMessages
        })
      });
      if (res.ok) {
        const body = await res.json();
        return {
          ok: true,
          text: body.content?.[0]?.text || '',
          stop_reason: body.stop_reason || null,
          input_tokens: body.usage?.input_tokens || 0,
          output_tokens: body.usage?.output_tokens || 0,
          attempts: attempt
        };
      }
      const errBody = await res.text();
      if (res.status === 429) await sleep(30000);
      lastErr = new Error(`HTTP ${res.status}: ${errBody.slice(0, 300)}`);
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || 'opus_coach failed', attempts: maxRetries };
}

const claudeStart = Date.now();
const claudeRes = await callClaude(4);
const claudeDuration = Date.now() - claudeStart;

const inputTokens = claudeRes.input_tokens || 0;
const outputTokens = claudeRes.output_tokens || 0;
// Opus 4.6 pricing: $15/M input, $75/M output
const costUsd = ((inputTokens * 15) + (outputTokens * 75)) / 1_000_000;
const costRounded = Math.round(costUsd * 10000) / 10000;

// Build context snapshot to persist alongside the user turn (for future audits)
const contextSnapshot = {
  project_id: data.project_id,
  niche_health_score: project.niche_health_score != null ? project.niche_health_score : null,
  niche_rpm_category: rpmCat,
  estimated_rpm_mid: rpmMid,
  recent_topics_count: (ctx.recent_topics || []).length,
  pps_range: ppsValues.length ? { min: minPps, max: maxPps } : null,
  avg_ctr_pct: avgCtr,
  unread_alert_count: alertCount,
  top_alert: topAlert || null,
  pending_ideas_count: ideaCount,
  focus_area: focusArea,
  system_prompt_char_len: systemPrompt.length,
  message_count_in_request: trimmedMessages.length
};

return [{
  json: {
    ...data,
    claude_ok: claudeRes.ok,
    claude_error: claudeRes.ok ? null : (claudeRes.error || 'unknown'),
    assistant_content: claudeRes.ok ? (claudeRes.text || '').trim() : '',
    stop_reason: claudeRes.stop_reason || null,
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    cost_usd: costRounded,
    duration_ms: claudeDuration,
    context_snapshot: contextSnapshot,
    system_prompt: systemPrompt
  }
}];

// Persist user + assistant turns, update session counters, log production_logs.
// On Claude failure: still persist the user turn + a system row so history is preserved,
// then respond success=false.

const data = $input.first().json;
if (data.success === false) return [{ json: data }];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const projectId = data.project_id;
const sessionId = data.session_id;
const prevMax = Number.isInteger(data.prev_max_turn_index) ? data.prev_max_turn_index : -1;
const userTurnIndex = prevMax + 1;
const assistantTurnIndex = prevMax + 2;
const nowIso = new Date().toISOString();
const claudeOk = data.claude_ok === true;
const userMessage = data.user_message;
const assistantContent = data.assistant_content || '';
const session = data.session || {};
const isNewSession = data.is_new_session === true;

async function sbPost(path, body, preferRepr) {
  return fetch(`${supabaseUrl}/rest/v1/${path}`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': preferRepr ? 'return=representation' : 'return=minimal' },
    body: JSON.stringify(body)
  });
}

async function sbPatch(path, body) {
  return fetch(`${supabaseUrl}/rest/v1/${path}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(body)
  });
}

async function logProduction(action, status, durationMs, costUsd) {
  try {
    await sbPost('production_logs', {
      project_id: projectId,
      topic_id: null,
      stage: 'ai_coach',
      scene_number: null,
      action,
      status,
      duration_ms: durationMs,
      cost_usd: costUsd,
      retry_count: 0
    }, false);
  } catch (_) { /* best-effort */ }
}

// 1. INSERT user turn (always — preserves history even if Claude failed)
let userTurnInserted = false;
let userInsertError = null;
let userRowId = null;
try {
  const res = await sbPost('coach_messages', {
    session_id: sessionId,
    project_id: projectId,
    turn_index: userTurnIndex,
    role: 'user',
    content: userMessage,
    context_snapshot: data.context_snapshot || null,
    input_tokens: null,
    output_tokens: null,
    cost_usd: null,
    claude_model: 'claude-opus-4-6',
    stop_reason: null
  }, true);
  if (res.ok) {
    const arr = await res.json();
    userTurnInserted = true;
    userRowId = Array.isArray(arr) && arr[0] ? arr[0].id : null;
  } else {
    userInsertError = `HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
  }
} catch (e) {
  userInsertError = e.message;
}

// 2. INSERT assistant turn — success path
// If Claude failed, insert a system row marker instead so the UI can show the state.
let assistantRowId = null;
let assistantInsertError = null;
let assistantRole = 'assistant';
let assistantContentPersisted = assistantContent;

if (!claudeOk || !assistantContent) {
  assistantRole = 'system';
  assistantContentPersisted = `[coach unavailable] ${data.claude_error || 'no response'}`.slice(0, 1000);
}

try {
  const res = await sbPost('coach_messages', {
    session_id: sessionId,
    project_id: projectId,
    turn_index: assistantTurnIndex,
    role: assistantRole,
    content: assistantContentPersisted,
    context_snapshot: null,
    input_tokens: claudeOk ? (data.input_tokens || 0) : null,
    output_tokens: claudeOk ? (data.output_tokens || 0) : null,
    cost_usd: claudeOk ? (data.cost_usd || 0) : null,
    claude_model: 'claude-opus-4-6',
    stop_reason: data.stop_reason || (claudeOk ? null : 'error')
  }, true);
  if (res.ok) {
    const arr = await res.json();
    assistantRowId = Array.isArray(arr) && arr[0] ? arr[0].id : null;
  } else {
    assistantInsertError = `HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
  }
} catch (e) {
  assistantInsertError = e.message;
}

// 3. UPDATE coach_sessions counters
// Compute new totals. turns_added = 2 if both turns actually wrote, else 1 (or 0 if neither).
const addedUser = userTurnInserted ? 1 : 0;
const addedAssistant = assistantRowId ? 1 : 0;
const addedTotal = addedUser + addedAssistant;

const newMessageCount = (Number(session.message_count) || 0) + addedTotal;
const newInputTokens = (Number(session.total_input_tokens) || 0) + (claudeOk ? (data.input_tokens || 0) : 0);
const newOutputTokens = (Number(session.total_output_tokens) || 0) + (claudeOk ? (data.output_tokens || 0) : 0);
const newEstCostUsd = Math.round(((Number(session.estimated_cost_usd) || 0) + (claudeOk ? (data.cost_usd || 0) : 0)) * 10000) / 10000;

// Auto-derive title from first user message if session.title is null AND this was the first turn.
const patch = {
  message_count: newMessageCount,
  total_input_tokens: newInputTokens,
  total_output_tokens: newOutputTokens,
  estimated_cost_usd: newEstCostUsd,
  last_message_at: nowIso,
  updated_at: nowIso
};

let derivedTitle = null;
if ((isNewSession || prevMax === -1) && !session.title) {
  derivedTitle = userMessage.slice(0, 60).replace(/\s+/g, ' ').trim() || null;
  if (derivedTitle) patch.title = derivedTitle;
}

let sessionPatchError = null;
try {
  const res = await sbPatch(`coach_sessions?id=eq.${sessionId}`, patch);
  if (!res.ok) sessionPatchError = `HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
} catch (e) {
  sessionPatchError = e.message;
}

// 4. production_logs
const logStatus = claudeOk && assistantRowId && userTurnInserted && !sessionPatchError
  ? 'success'
  : (claudeOk ? 'partial' : 'error');
await logProduction('turn_pair', logStatus, data.duration_ms || 0, data.cost_usd || 0);

// 5. Build response
const httpStatus = claudeOk ? 200 : 502;

return [{
  json: {
    success: claudeOk && !!assistantRowId && !sessionPatchError,
    session_id: sessionId,
    is_new_session: isNewSession,
    assistant_message: claudeOk ? {
      id: assistantRowId,
      content: assistantContent,
      cost_usd: data.cost_usd || 0,
      turn_index: assistantTurnIndex,
      input_tokens: data.input_tokens || 0,
      output_tokens: data.output_tokens || 0,
      stop_reason: data.stop_reason || null
    } : null,
    user_message: claudeOk ? null : {
      id: userRowId,
      turn_index: userTurnIndex,
      content: userMessage
    },
    session: {
      id: sessionId,
      message_count: newMessageCount,
      estimated_cost_usd: newEstCostUsd,
      title: derivedTitle || session.title || null,
      focus_area: session.focus_area || 'general'
    },
    error: claudeOk ? null : (data.claude_error || 'coach_call_failed'),
    user_insert_error: userInsertError,
    assistant_insert_error: assistantInsertError,
    session_patch_error: sessionPatchError,
    duration_ms: data.duration_ms || 0,
    http_status: httpStatus,
    via_webhook: data.via_webhook
  }
}];
